(((SELECT id FROM frameworks WHERE name = 'soc2-health')), 'SOC2-CC6.1-001', 'Unencrypted Data Transmission', 'Detects unencrypted HTTP usage in code or configuration.', 'critical', 'encryption', 'SOC2 CC6.1 - Logical and Physical Access Controls', 'Use HTTPS for all data transmission and enforce modern TLS.', 'negative_pattern', '{"regex":"http://(?!localhost|127\\.0\\.0\\.1|0\\.0\\.0\\.0)","exclude":["*.test.*","*.md"]}', 1),
